from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle different entities properly
    subject_triples: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Use the first subject as the main subject
    main_subject = triples[0].subject
    main_clauses: list[str] = []
    related_clauses: list[str] = []

    def get_clause(triple: Triple) -> str:
        p = triple.predicate
        o = triple.object.strip('"')  # remove surrounding quotes if present

        # Map predicates to natural‑language fragments
        if p == "category":
            return f"is a {o}"
        elif p == "country":
            return f"located in {o}"
        elif p == "location":
            return f"located in {o}"
        elif p == "municipality":
            return f"in the municipality of {o}"
        elif p == "state":
            return f"within the state of {o}"
        elif p == "district":
            return f"within the district of {o}"
        elif p in ("established", "foundingDate"):
            return f"established in {o}"
        elif p in ("owner", "owningOrganisation"):
            return f"owned by {o}"
        elif p == "inaugurationDate":
            return f"inaugurated on {o}"
        elif p == "capital":
            return f"whose capital is {o}"
        elif p == "legislature":
            return f"whose legislature is {o}"
        elif p == "dedicatedTo":
            return f"dedicated to {o}"
        elif p == "designer":
            return f"designed by {o}"
        elif p == "material":
            return f"made of {o}"
        elif p == "ethnicGroup":
            return f"with ethnic group {o}"
        elif p == "language":
            return f"where the language is {o}"
        elif p == "religion":
            return f"where the religion is {o}"
        elif p == "nearestCity":
            return f"nearest to {o}"
        elif p == "currency":
            return f"where the currency is {o}"
        elif p == "largestCity":
            return f"with largest city {o}"
        elif p == "leader":
            return f"led by {o}"
        elif p == "leaderTitle":
            return f"with leader title {o}"
        elif p.startswith("hasToIts"):
            direction = p.replace("hasToIts", "").lower()
            return f"has to its {direction} {o}"
        elif p == "nativeName":
            return f'native name is "{o}"'
        else:
            # Fallback for any unexpected predicate
            return f"{p} {o}"

    # Process main subject triples
    for triple in subject_triples.get(main_subject, []):
        main_clauses.append(get_clause(triple))

    # Process related subject triples (like country info)
    for sub, sub_triples in subject_triples.items():
        if sub != main_subject:
            for triple in sub_triples:
                clause = get_clause(triple)
                related_clauses.append(f"{sub} {clause}")

    # Build the sentence more naturally
    if main_clauses:
        # Start with the main subject and its direct attributes
        sentence_parts = [f"{main_subject}"]
        sentence_parts.extend(main_clauses)
        sentence = " ".join(sentence_parts)
    else:
        sentence = main_subject

    if related_clauses:
        # Add related information more smoothly - avoid repeating subject names
        # Find unique subjects from related clauses and group their info
        related_info = []
        for clause in related_clauses:
            # Remove the subject name repetition for cleaner flow
            parts = clause.split(" ", 1)
            if len(parts) == 2:
                related_info.append(parts[1])
            else:
                related_info.append(clause)

        # Use relative clause structure for better flow
        sentence += f", which is in {related_info[0]}" if related_info else sentence
        if len(related_info) > 1:
            sentence += f", where {', '.join(related_info[1:])}"

    sentence += "."
    return sentence

